// Kill-switch service worker.
// The old build-log site registered a service worker at this path that is
// still cached in visitors' browsers and serving stale pages. This replacement
// unregisters itself, wipes any caches it left behind, and reloads open tabs.
// Once you're confident everyone has picked this up, this file can be deleted.

self.addEventListener('install', () => {
  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  event.waitUntil((async () => {
    // Drop every cache the old worker created.
    const keys = await caches.keys();
    await Promise.all(keys.map((key) => caches.delete(key)));

    // Remove this registration so no worker intercepts future navigations.
    await self.registration.unregister();

    // Force any currently-open tabs to reload from the network.
    const clients = await self.clients.matchAll({ type: 'window' });
    clients.forEach((client) => client.navigate(client.url));
  })());
});
